import re
from collections import Counter

# Load businesses data
file_path = locals()['var_functions.query_db:32']
with open(file_path, 'r', encoding='utf-8') as f:
    businesses = json.load(f)

# Extract categories from descriptions
category_businesses = {}
business_categories = {}

for business in businesses:
    business_id = business['business_id']
    description = business.get('description', '')

    # Extract categories from description
    categories = []

    # Pattern 1: "services in X, Y, and Z"
    match = re.search(r'services in ([^.]+)', description, re.IGNORECASE)
    if match:
        cats_text = match.group(1)
        # Clean and split
        cats = [c.strip().rstrip('.') for c in cats_text.split(',')]
        cats = [c for c in cats if c and not c.startswith('and ')]
        categories.extend(cats)

    # Pattern 2: "including X, Y, and Z"
    if not categories:
        match = re.search(r'including ([^.]+)', description, re.IGNORECASE)
        if match:
            cats_text = match.group(1)
            cats = [c.strip().rstrip('.') for c in cats_text.split(',')]
            cats = [c for c in cats if c and not c.startswith('and ')]
            categories.extend(cats)

    # Standardize categories (title case, strip whitespace)
    cleaned_categories = []
    for cat in categories:
        cat = cat.strip()
        if cat.startswith('and '):
            cat = cat[4:]
        if cat:
            # Convert to title case for consistency
            cat = cat.title()
            cleaned_categories.append(cat)

    # If still no categories, use keyword matching
    if not cleaned_categories:
        desc_lower = description.lower()
        if 'restaurant' in desc_lower:
            cleaned_categories.append('Restaurants')
        elif 'food' in desc_lower:
            cleaned_categories.append('Food')
        elif 'beauty' in desc_lower or 'spa' in desc_lower or 'salon' in desc_lower:
            cleaned_categories.append('Beauty & Spas')
        elif 'shopping' in desc_lower or 'store' in desc_lower:
            cleaned_categories.append('Shopping')
        elif 'automotive' in desc_lower or 'auto' in desc_lower:
            cleaned_categories.append('Automotive')
        elif 'health' in desc_lower or 'medical' in desc_lower:
            cleaned_categories.append('Health & Medical')

    # Map business to categories
    business_categories[business_id] = cleaned_categories

    # Add to category count
    for cat in cleaned_categories:
        if cat not in category_businesses:
            category_businesses[cat] = []
        category_businesses[cat].append(business_id)

# Find the largest category
category_counts = {cat: len(biz_list) for cat, biz_list in category_businesses.items()}
if category_counts:
    largest_category = max(category_counts.items(), key=lambda x: x[1])

    print('__RESULT__:')
    print(json.dumps({
        'largest_category': largest_category[0],
        'business_count': largest_category[1],
        'category_businesses': category_businesses[largest_category[0]]
    }))
else:
    print('__RESULT__:')
    print(json.dumps({
        'error': 'No categories found'
    }))"}

